arguments.new_str:
using System.IO.Compression;
using System.Text;
class ZipCreator
{
    void CreateArchive()
    {
        // .NET 9 breaking change: ZipArchive now unconditionally sets the UTF-8
        // EFS flag (bit 11). Legacy consumers that expect Shift-JIS will misread
        // entry names. Fix: pass Shift-JIS encoding explicitly so the flag is
        // cleared and names are written in the encoding the Java system expects.
        Encoding.RegisterProvider(CodePagesEncodingProvider.Instance);
        var shiftJis = Encoding.GetEncoding("Shift_JIS");
        using var archive = ZipFile.Open("data.zip", ZipArchiveMode.Create, shiftJis);
        archive.CreateEntry("レポート/月次.csv");  // Japanese path
        archive.CreateEntry("données/résumé.txt"); // French accented
    }
}

